import fs from 'node:fs/promises';
import path from 'node:path';
import os from 'node:os';
import { execSync } from 'node:child_process';
import { ensureOpenClawModelsJson } from './src/agents/models-config.ts';
import { createProviderAuthResolver } from './src/agents/models-config.providers.secrets.ts';
import { discoverAuthStorage, discoverModels } from './src/agents/pi-model-discovery.ts';

const head = execSync('git rev-parse --short HEAD').toString().trim();
const root = await fs.mkdtemp(path.join(os.tmpdir(), 'openclaw-84581-catalog-proof-'));
const modelRow = (id) => ({ id, name: 'Proof Model', reasoning: false, input: ['text'], contextWindow: 8192, contextTokens: 8192, maxTokens: 64 });
const readJson = async (file) => JSON.parse(await fs.readFile(file, 'utf8'));

const inlineAgentDir = path.join(root, 'inline-custom-provider');
await fs.mkdir(inlineAgentDir, { recursive: true });
await ensureOpenClawModelsJson({ models: { providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', apiKey: 'sk-runtime-custom-key-proof', models: [modelRow('custom-model')] } } } }, inlineAgentDir);
const inlineModels = await readJson(path.join(inlineAgentDir, 'models.json'));
const inlineRegistry = discoverModels(discoverAuthStorage(inlineAgentDir, { skipCredentials: true }), inlineAgentDir, { normalizeModels: false });

const legacyAgentDir = path.join(root, 'legacy-models-json-only');
await fs.mkdir(legacyAgentDir, { recursive: true });
await fs.writeFile(path.join(legacyAgentDir, 'models.json'), JSON.stringify({ providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', apiKey: 'sk-existing-models-json-only-proof', models: [modelRow('legacy-model')] } } }, null, 2) + '\n');
await ensureOpenClawModelsJson({ models: { mode: 'merge', providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', models: [modelRow('legacy-model')] } } } }, legacyAgentDir);
const legacyModelsRaw = await fs.readFile(path.join(legacyAgentDir, 'models.json'), 'utf8');
const legacyModels = JSON.parse(legacyModelsRaw);
const legacyAuth = await readJson(path.join(legacyAgentDir, 'auth-profiles.json'));
const legacyRegistry = discoverModels(discoverAuthStorage(legacyAgentDir, { skipCredentials: true }), legacyAgentDir, { normalizeModels: false });

const catalogOnlyAgentDir = path.join(root, 'catalog-only-legacy-models-json');
await fs.mkdir(catalogOnlyAgentDir, { recursive: true });
await fs.writeFile(path.join(catalogOnlyAgentDir, 'models.json'), JSON.stringify({ providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', apiKey: 'sk-catalog-only-proof', models: [modelRow('catalog-only-model')] } } }, null, 2) + '\n');
await ensureOpenClawModelsJson({}, catalogOnlyAgentDir, { providerDiscoveryProviderIds: ['__no_provider_for_catalog_cleanup__'], providerDiscoveryEntriesOnly: true });
const catalogOnlyModelsRaw = await fs.readFile(path.join(catalogOnlyAgentDir, 'models.json'), 'utf8');
const catalogOnlyModels = JSON.parse(catalogOnlyModelsRaw);
const catalogOnlyAuth = await readJson(path.join(catalogOnlyAgentDir, 'auth-profiles.json'));
const catalogOnlyRegistry = discoverModels(discoverAuthStorage(catalogOnlyAgentDir, { skipCredentials: true }), catalogOnlyAgentDir, { normalizeModels: false });

const envNameAgentDir = path.join(root, 'catalog-only-env-name-models-json');
await fs.mkdir(envNameAgentDir, { recursive: true });
await fs.writeFile(path.join(envNameAgentDir, 'models.json'), JSON.stringify({ providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', apiKey: 'LITELLM_KEY', models: [] } } }, null, 2) + '\n');
await ensureOpenClawModelsJson({}, envNameAgentDir);
const envNameModels = await readJson(path.join(envNameAgentDir, 'models.json'));
const envNameAuth = await readJson(path.join(envNameAgentDir, 'auth-profiles.json'));
const envNameProfile = envNameAuth.profiles['custom:models-json'];
const envNameRuntimeAuth = createProviderAuthResolver({ LITELLM_KEY: 'sk-live-proof-secret' }, envNameAuth)('custom');

const failAgentDir = path.join(root, 'fail-closed');
await fs.mkdir(failAgentDir, { recursive: true });
const originalFailModels = JSON.stringify({ providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', apiKey: 'sk-fail-closed-proof', models: [] } } }, null, 2) + '\n';
await fs.writeFile(path.join(failAgentDir, 'models.json'), originalFailModels);
await fs.mkdir(path.join(failAgentDir, 'auth-profiles.json'));
let failClosed = { threw: false, message: '', modelsJsonUnchanged: false };
try {
  await ensureOpenClawModelsJson({ models: { mode: 'merge', providers: { custom: { baseUrl: 'https://custom.example/v1', api: 'openai-completions', models: [] } } } }, failAgentDir);
} catch (err) {
  failClosed = { threw: true, message: String(err?.message ?? err), modelsJsonUnchanged: await fs.readFile(path.join(failAgentDir, 'models.json'), 'utf8') === originalFailModels };
}

console.log(JSON.stringify({
  head,
  tempRoot: '<tmp>',
  inlineCustomProvider: {
    apiKeyMarker: inlineModels.providers.custom.apiKey,
    hasPlaintextInModelsJson: JSON.stringify(inlineModels).includes('sk-runtime-custom-key-proof'),
    discoverModelsFindsCustomModel: inlineRegistry.find('custom', 'custom-model')?.id ?? null,
  },
  legacyModelsJsonOnlyUpgrade: {
    apiKeyMarker: legacyModels.providers.custom.apiKey,
    hasPlaintextInModelsJson: legacyModelsRaw.includes('sk-existing-models-json-only-proof'),
    migratedProfile: { ...legacyAuth.profiles['custom:models-json'], key: '<redacted>' },
    discoverModelsFindsLegacyModel: legacyRegistry.find('custom', 'legacy-model')?.id ?? null,
  },
  catalogOnlyLegacyCleanup: {
    apiKeyMarker: catalogOnlyModels.providers.custom.apiKey,
    hasPlaintextInModelsJson: catalogOnlyModelsRaw.includes('sk-catalog-only-proof'),
    migratedProfile: { ...catalogOnlyAuth.profiles['custom:models-json'], key: '<redacted>' },
    discoverModelsFindsCatalogOnlyModel: catalogOnlyRegistry.find('custom', 'catalog-only-model')?.id ?? null,
  },
  envNameCatalogMigration: {
    modelsJsonPromptSafe: !Object.hasOwn(envNameModels.providers.custom, 'apiKey'),
    migratedProfile: {
      type: envNameProfile.type,
      provider: envNameProfile.provider,
      hasInlineKey: typeof envNameProfile.key === 'string',
      keyRef: envNameProfile.keyRef,
      copyToAgents: envNameProfile.copyToAgents,
    },
    runtimeAuth: {
      mode: envNameRuntimeAuth.mode,
      source: envNameRuntimeAuth.source,
      profileId: envNameRuntimeAuth.profileId,
      apiKeyMarker: envNameRuntimeAuth.apiKey,
      resolvedEnvValueSeen: envNameRuntimeAuth.discoveryApiKey === 'sk-live-proof-secret',
    },
  },
  failClosedMigrationPersistence: failClosed,
}, null, 2));
